# Book module providing core book types and operations

class Book:
    title: str
    author: str
    pages: int
    is_available: bool

    def __init__(self, title: str, author: str, pages: int):
        self.title = title
        self.author = author
        self.pages = pages
        self.is_available = True

    def checkout(self) -> bool:
        if self.is_available:
            self.is_available = False
            return True
        return False

    def return_book(self) -> None:
        self.is_available = True

    def get_info(self) -> str:
        status: str = "Available" if self.is_available else "Checked Out"
        return f"{self.title} by {self.author} ({self.pages} pages) - {status}"

def calculate_total_pages(books: list[Book]) -> int:
    total: int = 0
    for book in books:
        total += book.pages
    return total

