# Catalog module for managing collections of books

from book import Book, calculate_total_pages

class Library:
    name: str
    books: list[Book]

    def __init__(self, name: str):
        self.name = name
        self.books = []

    def add_book(self, book: Book) -> None:
        self.books.append(book)

    def get_available_count(self) -> int:
        count: int = 0
        for book in self.books:
            if book.is_available:
                count += 1
        return count

    def get_total_pages(self) -> int:
        return calculate_total_pages(self.books)
